### Progress with ETA

```rust
/// Helper for calculating ETA and throughput.
///
/// Use this alongside ProgressBar for time estimates.
pub struct ProgressWithEta {
    /// Current progress count
    current: u64,
    /// Total count
    total: u64,
    /// When tracking started
    started_at: Instant,
}

impl ProgressWithEta {
    pub fn new(total: u64) -> Self {
        debug!(total, "Creating ProgressWithEta");
        Self {
            current: 0,
            total,
            started_at: Instant::now(),
        }
    }

    /// Update current progress.
    pub fn set_current(&mut self, current: u64) {
        self.current = current.min(self.total);
    }

    /// Increment progress by one.
    pub fn inc(&mut self) {
        self.current = (self.current + 1).min(self.total);
    }

    /// Get completion ratio.
    pub fn ratio(&self) -> f64 {
        if self.total == 0 { 0.0 } else { self.current as f64 / self.total as f64 }
    }

    /// Get elapsed time.
    pub fn elapsed(&self) -> Duration {
        self.started_at.elapsed()
    }

    /// Estimate time remaining.
    pub fn eta(&self) -> Duration {
        if self.current == 0 {
            return Duration::MAX;
        }
        let elapsed = self.elapsed();
        let rate = self.current as f64 / elapsed.as_secs_f64();
        let remaining = self.total - self.current;
        Duration::from_secs_f64(remaining as f64 / rate)
    }

    /// Get items per second throughput.
    pub fn items_per_second(&self) -> f64 {
        let elapsed = self.elapsed().as_secs_f64();
        if elapsed == 0.0 { 0.0 } else { self.current as f64 / elapsed }
    }

    /// Format ETA as human-readable string.
    pub fn eta_string(&self) -> String {
        let eta = self.eta();
        if eta == Duration::MAX {
            "calculating...".to_string()
        } else if eta.as_secs() < 60 {
            format!("{}s", eta.as_secs())
        } else if eta.as_secs() < 3600 {
            format!("{}m {}s", eta.as_secs() / 60, eta.as_secs() % 60)
        } else {
            format!("{}h {}m", eta.as_secs() / 3600, (eta.as_secs() % 3600) / 60)
        }
    }
}
