#[cfg(test)]
mod tests {
    use super::*;
    use tracing_test::traced_test;

    // --- Spinner Tests ---

    #[test]
    fn test_spinner_frame_cycling() {
        let spinner = Spinner::new();
        let mut state = SpinnerState::new();
        let total = spinners::DOTS.len();

        for expected in 0..total * 2 {
            assert_eq!(state.frame, expected % total);
            state.tick(total, 1);
        }
    }

    #[test]
    fn test_spinner_with_label() {
        let spinner = Spinner::new().label("Loading...");
        // Should render spinner + " Loading..."
        let area = Rect::new(0, 0, 20, 1);
        let mut buf = Buffer::empty(area);
        let mut state = SpinnerState::new();
        spinner.render(area, &mut buf, &mut state);
        // Verify label is rendered
    }

    #[test]
    fn test_spinner_speed_control() {
        let spinner = Spinner::new().speed(2);
        let mut state = SpinnerState::new();
        let total = spinners::DOTS.len();

        // Should take 2 ticks to advance frame
        state.tick(total, 2);
        assert_eq!(state.frame, 0); // Not advanced yet
        state.tick(total, 2);
        assert_eq!(state.frame, 1); // Now advanced
    }

    // --- ProgressBar Tests ---

    #[test]
    fn test_progress_bar_empty() {
        let bar = ProgressBar::new().ratio(0.0);
        let area = Rect::new(0, 0, 10, 1);
        let mut buf = Buffer::empty(area);
        bar.render(area, &mut buf);
        // All empty chars
    }

    #[test]
    fn test_progress_bar_full() {
        let bar = ProgressBar::new().ratio(1.0);
        let area = Rect::new(0, 0, 10, 1);
        let mut buf = Buffer::empty(area);
        bar.render(area, &mut buf);
        // All filled chars
    }

    #[test]
    fn test_progress_bar_half() {
        let bar = ProgressBar::new().ratio(0.5);
        let area = Rect::new(0, 0, 10, 1);
        let mut buf = Buffer::empty(area);
        bar.render(area, &mut buf);
        // 5 filled, 5 empty
    }

    #[test]
    fn test_progress_bar_overflow() {
        let bar = ProgressBar::new().ratio(1.5); // Over 100%
        assert!((bar.ratio - 1.0).abs() < f64::EPSILON); // Clamped to 1.0
    }

    #[test]
    fn test_progress_from_count() {
        let bar = ProgressBar::new().progress(50, 100);
        assert!((bar.ratio - 0.5).abs() < f64::EPSILON);
    }

    #[test]
    fn test_progress_with_label() {
        let bar = ProgressBar::new().ratio(0.5).with_percentage_label();
        assert_eq!(bar.label, Some("50%".to_string()));
    }

    // --- ProgressWithEta Tests ---

    #[test]
    fn test_eta_calculation() {
        let mut progress = ProgressWithEta::new(100);
        // Simulate some elapsed time
        std::thread::sleep(Duration::from_millis(100));
        progress.set_current(50);

        let eta = progress.eta();
        // ETA should be roughly equal to elapsed (50% done in 100ms = 100ms remaining)
        assert!(eta.as_millis() > 50 && eta.as_millis() < 200);
    }

    #[test]
    fn test_items_per_second() {
        let mut progress = ProgressWithEta::new(100);
        std::thread::sleep(Duration::from_millis(100));
        progress.set_current(10);

        let rate = progress.items_per_second();
        // Should be roughly 100 items/sec (10 items in 100ms)
        assert!(rate > 50.0 && rate < 200.0);
    }

    #[test]
    fn test_wide_character_spinner() {
        let spinner = Spinner::new().preset(spinners::MOON);
        let area = Rect::new(0, 0, 10, 1);
        let mut buf = Buffer::empty(area);
        let mut state = SpinnerState::new();
        spinner.render(area, &mut buf, &mut state);
        // Should handle wide emoji correctly
    }
}
